-- Redshift: manual distribution + sort key + maintenance required
CREATE TABLE orders (
  order_id BIGINT,
  customer_id BIGINT,
  created_at TIMESTAMP,
  amount NUMERIC(10,2)
)
DISTKEY(customer_id)
SORTKEY(created_at);

VACUUM orders TO 95 PERCENT;
ANALYZE orders;

-- BigQuery equivalent: partitioning + clustering, no VACUUM/ANALYZE
CREATE TABLE `project.dataset.orders`
PARTITION BY DATE(created_at)
CLUSTER BY customer_id AS
SELECT * FROM source;

-- BigQuery: FOR SYSTEM_TIME AS OF '2024-01-01'
-- Databricks Delta Lake equivalent:
SELECT * FROM sales_delta VERSION AS OF 42;
SELECT * FROM sales_delta TIMESTAMP AS OF '2024-01-01T00:00:00';

-- BigQuery clustering → Delta Z-ordering (manual, not automatic)
OPTIMIZE sales_delta
  ZORDER BY (customer_id, event_date);

-- BigQuery automatic expiry → explicit VACUUM in Delta
VACUUM sales_delta RETAIN 168 HOURS;

-- Unity Catalog: catalog.schema.table (vs BQ project.dataset.table)
SELECT * FROM prod_catalog.sales_schema.transactions
WHERE region = 'US';
